<p class="wp-block-paragraph">Anak muda memainkan peran penting dalam pembuatan dan berbagi konten dengan menggunakan platform media sosial secara aktif.</p>', '$.wp_published_at', '2026-02-27T03:00:00Z', '$.wp_modified_at', '2026-03-06T10:13:20Z') WHERE "collection" = 'posts' AND "id" = ( SELECT "live_revision_id" FROM "ec_posts" WHERE "deleted_at" IS NULL AND "status" = 'published' AND "locale" = 'id' AND "slug" = 'media-sosial-dan-pembuatan-konten-di-turki' );
